"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["23092"],{41778(t){t.exports=JSON.parse('{"tag":{"label":"transport","permalink":"/sysanalyst-kb.github.io/tech/tags/transport","allTagsPath":"/sysanalyst-kb.github.io/tech/tags","count":1,"items":[{"id":"tms","title":"TMS \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043A\u0430\u043C\u0438","description":"TMS (Transportation Management System) \u2014 \u043A\u043B\u0430\u0441\u0441 \u0441\u0438\u0441\u0442\u0435\u043C \u0434\u043B\u044F \u043F\u043B\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u0438\u0441\u043F\u043E\u043B\u043D\u0435\u043D\u0438\u044F \u0438 \u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044F \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442\u0438\u0440\u043E\u0432\u043A\u0438 \u0433\u0440\u0443\u0437\u043E\u0432. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u0432\u0435\u043D\u0434\u043E\u0440\u044BTMS (\u0420\u0424), SAP TM (enterprise), Oracle OTM, Solomon TMS (SaaS, \u0440\u0438\u0442\u0435\u0439\u043B), RetaiLite. TMS \u0440\u0435\u0448\u0430\u0435\u0442 \u0437\u0430\u0434\u0430\u0447\u0438: \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u044F, \u0443\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u0447\u0438\u043A\u0430\u043C\u0438, \u0442\u0430\u0440\u0438\u0444\u0438\u043A\u0430\u0446\u0438\u044F, \u0442\u0440\u0435\u043A\u0438\u043D\u0433, \u042D\u0414\u041E, \u0432\u0437\u0430\u0438\u043C\u043E\u0440\u0430\u0441\u0447\u0451\u0442\u044B. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043D\u0430 \u043F\u0440\u043E\u0435\u043A\u0442\u0435 TMS \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442 \u0431\u0438\u0437\u043D\u0435\u0441-\u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u043F\u0435\u0440\u0435\u0432\u043E\u0437\u043E\u043A, \u043D\u0430\u0441\u0442\u0440\u0430\u0438\u0432\u0430\u0435\u0442 \u0442\u0430\u0440\u0438\u0444\u043D\u044B\u0435 \u0441\u0445\u0435\u043C\u044B, \u0438\u043D\u0442\u0435\u0433\u0440\u0438\u0440\u0443\u0435\u0442 TMS \u0441 WMS/ERP \u0438 \u043F\u0440\u043E\u0432\u0430\u0439\u0434\u0435\u0440\u0430\u043C\u0438 \u042D\u0414\u041E.","permalink":"/sysanalyst-kb.github.io/tech/tms"}],"unlisted":false}}')}}]);